// // This module implements a 20-bit shift register with parallel load, shift right, and set signal.
// The register loads a given value when load is low, shifts right when shift_right is low, and sets to 1 when set is high.
module top_module(
	input clk,
	input load,
	input shift_left,
	input clear,
	input [19:0] load_value,
	output reg [19:0] q);
always @(posedge clk) begin
	if (clear)
		q <= 0;
	else if (load)
		q <= load_value;
	else if (shift_left)
		q <= q << 1;
end

endmodule
